// Funksiya tiplərinin sintaksisi
function add(a: number, b: number): number {
  return a + b;
}

type MathOperation = (x: number, y: number) => number;

interface Calculator {
  subtract: (x: number, y: number) => number;
}

let multiply: MathOperation = (x, y) => x * y;
let calc: Calculator = { subtract: (x, y) => x - y };

console.log(add(5, 3)); // 8
console.log(multiply(5, 3)); // 15
console.log(calc.subtract(5, 3)); // 2
// add('5', '3'); // Xəta: string number-ə təyin edilə bilməz

// Opsional və default parametrlər
function greet(name: string, greeting?: string, prefix: string = 'Hello'): string {
  return `${prefix}, ${greeting ?? 'welcome'} ${name}!`;
}

console.log(greet('Ali')); // Hello, welcome Ali!
console.log(greet('Vəli', 'salam')); // Hello, salam Vəli!
console.log(greet('Ayşə', 'salam', 'Hi')); // Hi, salam Ayşə!
// greet(42); // Xəta: number string-ə təyin edilə bilməz

// Rest parametrləri
function sum(...numbers: number[]): number {
  return numbers.reduce((total, num) => total + num, 0);
}

console.log(sum(1, 2, 3)); // 6
console.log(sum(10)); // 10
console.log(sum()); // 0
// sum('1', '2'); // Xəta: string number-ə təyin edilə bilməz

// Funksiya overloading-i
function combine(a: string, b: string): string;
function combine(a: number, b: number): number;
function combine(a: string | number, b: string | number): string | number {
  if (typeof a === 'string' && typeof b === 'string') {
    return a + b;
  }
  if (typeof a === 'number' && typeof b === 'number') {
    return a + b;
  }
  throw new Error('Uyğun olmayan tiplər');
}

console.log(combine('Hello', 'World')); // HelloWorld
console.log(combine(5, 3)); // 8
// combine('Hello', 3); // Xəta: uyğun overloading yoxdur

// Anonim funksiyalar
let divide: (a: number, b: number) => number = function (a, b) {
  return a / b;
};

console.log(divide(10, 2)); // 5
// divide('10', '2'); // Xəta: string number-ə təyin edilə bilməz

// Praktik nümunə
interface Product {
  id: number;
  name: string;
  price: number;
}

type ProductFilter = (products: Product[], minPrice: number) => Product[];

const filterExpensive: ProductFilter = (products, minPrice) => {
  return products.filter(product => product.price > minPrice);
};

let products: Product[] = [
  { id: 1, name: 'Telefon', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
  { id: 3, name: 'Planşet', price: 300 },
];

console.log(filterExpensive(products, 500)); // [{ id: 2, name: 'Laptop', price: 1000 }]

// Təhlükəsizlik nümunəsi
function safeAdd(a: number, b: number): number {
  return a + b;
}

console.log(safeAdd(5, 3)); // 8
// safeAdd('5', '3'); // Xəta: string number-ə təyin edilə bilməz

// Səhvə yol açan nümunə
let unsafe: any = (a, b) => a + b;
console.log(unsafe('Hello', 42)); // Hello42 (təhlükəsiz deyil, runtime səhvi ola bilər)

// Düzgün yol
let safe: (a: number, b: number) => number = (a, b) => a + b;
console.log(safe(5, 3)); // 8
// safe('5', '3'); // Xəta: string number-ə təyin edilə bilməz

// Real layihə ssenarisi
interface User {
  id: number;
  name: string;
}

type UserFormatter = (user: User) => string;

const formatUser: UserFormatter = (user) => {
  return `ID: ${user.id}, Name: ${user.name}`;
};

let user: User = { id: 1, name: 'Ali' };
console.log(formatUser(user)); // ID: 1, Name: Ali

